// PATRÓN PARA TUS PIPELINES REALES:
// en cada etapa de tu SaaS Factory, emite task.start antes de trabajar
// y task.done al terminar. Aquí las "etapas" son pausas de ejemplo —
// en tu pipeline real serían tus nodos de verdad (crear repo, desplegar, etc.)
const base = 'https://n8n-n8n.gpr07a.easypanel.host/webhook/factory-event';
const project = ($json.body && $json.body.project) || 'Proyecto desde n8n';
const post = (ev) => this.helpers.httpRequest({ method: 'POST', url: base, body: ev, json: true });
const sleep = (ms) => new Promise(r => setTimeout(r, ms));

await post({ type: 'project.start', project });

const etapas = [
  ['Nova', 'definió la arquitectura y los módulos', 3500],
  ['Byte', 'construyó el backend y desplegó la API', 5000],
  ['Vega', 'validó métricas y datos de prueba', 3500],
  ['Mila', 'preparó la campaña de lanzamiento', 3500],
  ['Eco', 'publicó el anuncio para la comunidad', 3000]
];

for (const [agent, detail, ms] of etapas) {
  await post({ type: 'task.start', agent, project, detail: 'inició: ' + detail });
  await sleep(ms); // <-- aquí va tu trabajo real
  await post({ type: 'task.done', agent, project, detail });
}

await post({ type: 'project.done', project });
return [{ json: { ok: true, project } }];
